    Map<String, Integer> precedence = new HashMap<String, Integer>();
    precedence.put("+",1);
    precedence.put("-",1);
    precedence.put("*",2);
    precedence.put("/",2);
    ArrayList rpntokens = new ArrayList(100);
    ArrayDeque opstack = new ArrayDeque();
    for (Object token: tokens) {
