            while (!opstack.isEmpty() && precedence.get(operator) <= precedence.get(opstack.getLast())) {
                rpntokens.add(opstack.pop());
            }
        }
    }
    while (!opstack.isEmpty()) {
        rpntokens.add(opstack.pop());
    }
    return rpntokens;
}

